function handleUserInput() {
  var inputEl = document.getElementById('ai-input-field');
  if (!inputEl) return;
  var text = inputEl.value.trim();
  if (!text) return;
  aiChatHistory.push({ text: text, sender: 'user' });
  inputEl.value = '';
  renderAIChat();
  addTypingIndicator();
  var lowerText = text.toLowerCase();
  if (lowerText.match(/whatsapp|human|person|staff|agent|delivery|available|availability|pay|payment|mpesa|m-pesa|order|buy/)) {
    setTimeout(function() {
      removeTypingIndicator();
      addAIMessage('A real team member can close this faster on WhatsApp with availability, delivery fee, and payment steps.');
      addAIWhatsAppPrompt('Send this request to WhatsApp now.');
    }, 500);
    return;
  }
  if (lowerText.match(/^(hi|hey|hello|yo|sup|hiya|heya)/)) {
    setTimeout(function() {
      removeTypingIndicator();
      addAIMessage('Hi! Tell me who is playing, the occasion, and your budget. Final orders are confirmed on WhatsApp.');
    }, 500);
    return;
  }
  if (lowerText.length < 3) {
    setTimeout(function() {
      removeTypingIndicator();
      addAIMessage('Tell me a little more so I can recommend the right game.');
    }, 500);
    return;
  }
  setTimeout(function() {
    removeTypingIndicator();
    processGameSearch(text);
  }, 650);
}

function processGameSearch(text) {
  var lowerText = text.toLowerCase();
  parseUserInput(text);
  if (!aiState.type) {
    var guessedType = guessGameTypeFromText(lowerText);
    if (guessedType) aiState.type = guessedType;
  }
  if (!aiState.players) {
    var playerMatch = lowerText.match(/(\d+)\s*(players?|people|friends?)/);
    if (playerMatch) aiState.players = parseInt(playerMatch[1]);
    else if (lowerText.includes('couple') || lowerText.includes('two')) aiState.players = 2;
    else if (lowerText.includes('group') || lowerText.includes('party') || lowerText.includes('everyone')) aiState.players = 5;
  }
  if (!aiState.age) {
    if (lowerText.includes('kid') || lowerText.includes('children')) aiState.age = 'kids';
    else if (lowerText.includes('teen')) aiState.age = 'teens';
    else if (lowerText.includes('adult') || lowerText.includes('18')) aiState.age = 'adults';
    else if (lowerText.includes('family')) aiState.age = 'all';
  }
  if (!aiState.type && !aiState.players) {
    addAIMessage('I can help. How many people are playing, and should it feel party, strategy, romantic, educational, or family-friendly?');
    addAIWhatsAppPrompt('Or send this request to WhatsApp and our staff will help.');
    return;
  }
  if (!aiState.type) {
    addAIMessage('Got it for ' + aiState.players + ' players. What vibe should it have: party, strategy, romantic, educational, or family-friendly?');
    return;
  }
  addAIMessage('I found a few good matches. Tap a game for details, or send the shortlist to WhatsApp for availability and delivery.');
  var results = getAIRecommendations();
  if (results.length === 0) {
    results = getBestsellers().slice(0, 3).map(function(p) {
      return { product: p, reason: 'customer favorite' };
    });
  }
  results.forEach(function(r) {
    aiChatHistory.push({ product: r.product, reason: r.reason || 'recommended' });
  });
  addAIWhatsAppPrompt('Send these recommendations to WhatsApp.');
  renderAIChat();
}

