function parseUserInput(input) {
  input = input.toLowerCase();
  var newState = { ...aiState };
  
  if (input.match(/(\d+)\s*(player|people)/) || input.match(/^(two|three|four|five|six|seven|eight)$/)) {
    var num = input.match(/\d+/);
    if (num) newState.players = parseInt(num[0]);
    else if (input.includes('two') || input.includes('2')) newState.players = 2;
    else if (input.includes('three') || input.includes('3')) newState.players = 3;
    else if (input.includes('four') || input.includes('4')) newState.players = 4;
    else if (input.includes('five') || input.includes('5') || input.includes('6') || input.includes('seven') || input.includes('8')) newState.players = 5;
  }
  
  if (input.includes('kid')) newState.age = 'kids';
  else if (input.includes('teen')) newState.age = 'teens';
  else if (input.includes('adult')) newState.age = 'adults';
  else if (input.includes('family') || input.includes('all ages')) newState.age = 'all';
  
  if (input.includes('strategy')) newState.type = 'strategy';
  else if (input.includes('party')) newState.type = 'party';
  else if (input.includes('educat') || input.includes('learn')) newState.type = 'educational';
  else if (input.includes('romantic') || input.includes('couple')) newState.type = 'romantic';
  
  if (input.includes('easy') || input.includes('simple')) newState.difficulty = 'easy';
  else if (input.includes('medium') || input.includes('moderate')) newState.difficulty = 'medium';
  else if (input.includes('hard') || input.includes('challeng')) newState.difficulty = 'hard';
  
  aiState = newState;
}

function getAIRecommendations() {
  var products = PRODUCTS.map(function(p) {
    var score = 0;
    var reasons = [];
    
    if (aiState.type && (p.cat === 'party-games' || p.cat === 'card-games') && aiState.type === 'party') {
      score += 4; reasons.push('party game');
    }
    if (aiState.type && p.cat === 'couples-games' && aiState.type === 'romantic') {
      score += 4; reasons.push('couples game');
    }
    if (aiState.type && (p.cat === 'kids-games' || p.cat === 'puzzles' || p.cat === 'stem-toys') && aiState.type === 'educational') {
      score += 4; reasons.push('educational');
    }
    if (aiState.type && p.cat === 'board-games' && aiState.type === 'strategy') {
      score += 4; reasons.push('strategy game');
    }
    
    if (aiState.age === 'kids' && (p.cat === 'kids-games' || p.cat === 'puzzles' || p.cat === 'dolls' || p.cat === 'infant-toys' || p.cat === 'stem-toys')) {
      score += 3; reasons.push('for kids');
    }
    if (aiState.age === 'adults' && !p.adult) score -= 1;
    if (p.adult && aiState.age !== 'adults') score -= 2;
    
    if (aiState.difficulty && p.difficulty === aiState.difficulty) {
      score += 2; reasons.push(aiState.difficulty + ' difficulty');
    }
    
    if (p.badge === 'BESTSELLER' || p.badge === 'NEW' || p.badge === 'GIFT PICKS') {
      score += 1; reasons.push(p.badge.toLowerCase());
    }
    
    return { product: p, score: score, reason: reasons.join(' • ') || 'recommended' };
  });
  
  return products.filter(function(x) { return x.score > 0; })
    .sort(function(a, b) { return b.score - a.score; })
    .slice(0, 3);
}

