function guessGameTypeFromText(text) {
  if (text.match(/fun|party|laugh|crazy|wild|exciting/)) return 'party';
  if (text.match(/strateg|think|plan|skill/)) return 'strategy';
  if (text.match(/romantic|couple|date|intimate|love/)) return 'romantic';
  if (text.match(/learn|educational|kid|teach|skill/)) return 'educational';
  if (text.match(/drink|alcohol|beer|wine|buzz/)) return 'party';
  return null;
}

function giveSuggestion() {
  var suggestions = [
    "What vibe are you going for?",
    "Any preference on game style?",
    "Are you looking for something fun, strategic, or romantic? 🤔"
  ];
  return suggestions[Math.floor(Math.random() * suggestions.length)];
}

